": \"User\",\n      \"description\": \"User profiles restricted to owner.\"\n    },\n    \"/assessments/{assessmentId}\": {\n      \"schema\": \"Assessment\",\n      \"description\": \"Historical assessments for a user.\"\n    }\n  }\n}\n"
