    "path": "index.html",
    "content": "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <title>MedTriage AI | Clinical Symptom Assessment</title>\n    <script>\n      // Instantly suppress benign Vite HMR websocket connection errors in sandbox\n      (function() {\n        const isBenign = (err) => {\n          if (!err) return true;\n          try {\n            const str = typeof err === 'object' ? JSON.stringify(err) : String(err);\n            if (\n              /websocket/i.test(str) ||\n              /vite/i.test(str) ||\n              /ws:\\/\\/|wss:\\/\\//i.test(str) ||\n              /closed without opened/i.test(str) ||\n              /hmr/i.test(str)\n            ) {\n              return true;\n            }\n          } catch (e) {}\n          const msg = String(err.message || err.reason || err.description || err || '');\n          const stack = String(err.stack || '');\n          return (\n            msg.includes('WebSocket') ||\n            msg.includes('vite') ||\n            msg.includes('ws://') ||\n            msg.includes('wss://') ||\n            msg.includes('closed without opened') ||\n            stack.includes('vite') ||\n            stack.includes('hmr')\n          );\n        };\n        window.addEventListener('unhandledrejection', function(e) {\n          if (isBenign(e.reason)) {\n            e.preventDefault();\n            e.stopPropagation();\n          }\n        }, true);\n        window.addEventListener('error', function(e) {\n          if (isBenign(e.message) || isBenign(e.error) || isBenign(e)) {\n            e.preventDefault();\n            e.stopPropagation();\n          }\n        }, true);\n      })();\n    </script>\n  </head>\n  <body>\n    <div id=\"root\"></div>\n    <script type=\"module\" src=\"/src/main.tsx\"></script>\n  </body>\n</html>\n\n"
